1	//! Section CRUD + versioning workflow.
2	//!
3	//! Sections belong to a course and carry per-term scheduling data:
4	//! section_code, term, year, capacity, assigned instructor, location,
5	//! schedule, and notes. Version history follows the same state machine
6	//! (draft → approved → published → archived) as journals, resources,
7	//! and courses.
8	//!
9	//! # Authorization layers
10	//!
11	//! * `Capability::SectionWrite` gates edits at the role layer.
12	//! * `ensure_section_in_scope` additionally verifies that:
13	//!   - Admin / DepartmentHead can edit any section in their department.
14	//!   - Instructors can only edit sections where they are the assigned
15	//!     `instructor_id`.
16	//! * `Capability::SectionApprove` / `SectionPublish` further narrow
17	//!   approval/publish to DepartmentHead + Admin per the RBAC matrix.
18	
19	use chrono::NaiveDateTime;
20	use serde::{Deserialize, Serialize};
21	use sqlx::{MySqlPool, Row};
22	use uuid::Uuid;
23	
24	use super::audit_service::{self, AuditEvent};
25	use super::authorization::{principal_can, require, Capability};
26	use super::principal::{Principal, Role};
27	use crate::domain::versioning::{validate_transition, VersionState};
28	use crate::errors::{AppError, AppResult};
29	
30	// ---------------------------------------------------------------------------
31	// Inputs and view models
32	// ---------------------------------------------------------------------------
33	
34	#[derive(Debug, Clone, Deserialize)]
35	pub struct SectionCreateInput {
36	    pub course_id: Uuid,
37	    pub section_code: String,
38	    pub term: String, // "fall" | "spring" | "summer" | "winter"
39	    pub year: i32,
40	    pub capacity: i32,
41	    pub instructor_id: Option<Uuid>,
42	    pub location: Option<String>,
43	    pub schedule_note: Option<String>,
44	    pub notes: Option<String>,
45	}
46	
47	#[derive(Debug, Clone, Deserialize)]
48	pub struct SectionEditInput {
49	    pub instructor_id: Option<Uuid>,
50	    pub capacity: Option<i32>,
51	    pub location: Option<String>,
52	    pub schedule_note: Option<String>,
53	    pub notes: Option<String>,
54	    pub change_summary: Option<String>,
55	}
56	
57	#[derive(Debug, Clone, Serialize)]
58	pub struct SectionView {
59	    pub id: Uuid,
60	    pub course_id: Uuid,
61	    pub course_code: String,
62	    pub department_id: Option<Uuid>,
63	    pub section_code: String,
64	    pub term: String,
65	    pub year: i32,
66	    pub capacity: Option<i32>,
67	    pub instructor_id: Option<Uuid>,
68	    pub is_active: bool,
69	    pub current_version_id: Option<Uuid>,
70	    pub latest_version_id: Option<Uuid>,
71	    pub created_at: NaiveDateTime,
72	    pub updated_at: NaiveDateTime,
73	    pub effective_version: Option<SectionVersionView>,
74	}
75	
76	#[derive(Debug, Clone, Serialize)]
77	pub struct SectionVersionView {
78	    pub id: Uuid,
79	    pub section_id: Uuid,
80	    pub version_number: i32,
81	    pub location: Option<String>,
82	    pub schedule_note: Option<String>,
83	    pub notes: Option<String>,
84	    pub state: VersionState,
85	    pub created_by: Option<Uuid>,
86	    pub created_at: NaiveDateTime,
87	    pub approved_at: Option<NaiveDateTime>,
88	    pub published_at: Option<NaiveDateTime>,
89	}
90	
91	// ---------------------------------------------------------------------------
92	// Validation
93	// ---------------------------------------------------------------------------
94	
95	const SECTION_CODE_MAX: usize = 20;
96	const LOCATION_MAX: usize = 255;
97	const SCHEDULE_MAX: usize = 500;
98	const NOTES_MAX: usize = 2_000;
99	const CAPACITY_MIN: i32 = 1;
100	const CAPACITY_MAX: i32 = 1_000;
101	const YEAR_MIN: i32 = 2000;
102	const YEAR_MAX: i32 = 2100;
103	
104	pub const VALID_TERMS: &[&str] = &["fall", "spring", "summer", "winter"];
105	
106	pub fn is_valid_term(term: &str) -> bool {
107	    VALID_TERMS.iter().any(|t| t.eq_ignore_ascii_case(term))
108	}
109	
110	pub fn normalize_term(term: &str) -> String {
111	    term.trim().to_lowercase()
112	}
113	
114	pub fn is_valid_section_code(code: &str) -> bool {
115	    let t = code.trim();
116	    if t.is_empty() || t.len() > SECTION_CODE_MAX {
117	        return false;
118	    }
119	    t.chars().all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_')
120	}

1	/// Repository implementations — MySQL-backed persistence for each domain aggregate.
2	///
3	/// Each submodule implements the repository trait (or interface) for a
4	/// specific domain entity, translating between domain types and database
5	/// rows via sqlx queries.
6	
7	pub mod user_repo;
8	pub mod role_repo;
9	pub mod journal_repo;
10	pub mod resource_repo;
11	pub mod course_repo;
12	pub mod section_repo;
13	pub mod checkin_repo;
14	pub mod metric_repo;
15	pub mod dashboard_repo;
16	pub mod report_repo;
17	pub mod audit_repo;
18	pub mod retention_repo;
19	pub mod attachment_repo;
20

1	/// Section repository — MySQL-backed persistence for course section entities.
2	
3	pub struct SectionRepository {
4	    // TODO: Add MySqlPool field and implement query methods in Phase 2
5	}
6

120	}
121	
122	pub fn validate_capacity(cap: i32) -> AppResult<()> {
123	    if !(CAPACITY_MIN..=CAPACITY_MAX).contains(&cap) {
124	        return Err(AppError::Validation(format!(
125	            "capacity must be between {} and {}",
126	            CAPACITY_MIN, CAPACITY_MAX
127	        )));
128	    }
129	    Ok(())
130	}
131	
132	pub fn validate_year(year: i32) -> AppResult<()> {
133	    if !(YEAR_MIN..=YEAR_MAX).contains(&year) {
134	        return Err(AppError::Validation(format!(
135	            "year must be between {} and {}",
136	            YEAR_MIN, YEAR_MAX
137	        )));
138	    }
139	    Ok(())
140	}
141	
142	fn validate_optional(field: &str, value: Option<&str>, max: usize) -> AppResult<()> {
143	    if let Some(v) = value {
144	        if v.chars().count() > max {
145	            return Err(AppError::Validation(format!(
146	                "{} exceeds {} character limit",
147	                field, max
148	            )));
149	        }
150	    }
151	    Ok(())
152	}
153	
154	fn validate_section_inputs(
155	    section_code: &str,
156	    term: &str,
157	    year: i32,
158	    capacity: i32,
159	    location: Option<&str>,
160	    schedule: Option<&str>,
161	    notes: Option<&str>,
162	) -> AppResult<()> {
163	    if !is_valid_section_code(section_code) {
164	        return Err(AppError::Validation(format!(
165	            "section_code '{}' is invalid (alphanumeric + -/_, max {})",
166	            section_code, SECTION_CODE_MAX
167	        )));
168	    }
169	    if !is_valid_term(term) {
170	        return Err(AppError::Validation(format!(
171	            "term must be one of: {}",
172	            VALID_TERMS.join(", ")
173	        )));
174	    }
175	    validate_year(year)?;
176	    validate_capacity(capacity)?;
177	    validate_optional("location", location, LOCATION_MAX)?;
178	    validate_optional("schedule_note", schedule, SCHEDULE_MAX)?;
179	    validate_optional("notes", notes, NOTES_MAX)?;
180	    Ok(())
181	}
182	
183	// ---------------------------------------------------------------------------
184	// Public API
185	// ---------------------------------------------------------------------------
186	
187	pub async fn create_section(
188	    pool: &MySqlPool,
189	    principal: &Principal,
190	    input: SectionCreateInput,
191	) -> AppResult<SectionView> {
192	    require(principal, Capability::SectionWrite)?;
193	    validate_section_inputs(
194	        &input.section_code,
195	        &input.term,
196	        input.year,
197	        input.capacity,
198	        input.location.as_deref(),
199	        input.schedule_note.as_deref(),
200	        input.notes.as_deref(),
201	    )?;
202	
203	    // The course must exist and be in scope.
204	    let (course_code, course_dept) = load_course_meta(pool, input.course_id).await?;
205	    ensure_dept_scope(principal, course_dept)?;
206	
207	    // Instructor-only scope: an Instructor without admin/dept-head role
208	    // must assign themself (or no instructor at all).
209	    if principal.has_role(Role::Instructor)
210	        && !principal.is_admin()
211	        && !principal.has_role(Role::DepartmentHead)
212	    {
213	        if let Some(assigned) = input.instructor_id {
214	            if assigned != principal.user_id {
215	                return Err(AppError::Forbidden);
216	            }
217	        }
218	    }
219	
220	    // Instructor user, if any, must exist.
221	    if let Some(instr) = input.instructor_id {
222	        let exists = sqlx::query("SELECT 1 FROM users WHERE id = ? LIMIT 1")
223	            .bind(instr.to_string())
224	            .fetch_optional(pool)
225	            .await
226	            .map_err(|e| AppError::Database(format!("instructor lookup: {}", e)))?;
227	        if exists.is_none() {
228	            return Err(AppError::Validation(format!(
229	                "instructor {} does not exist",
230	                instr
231	            )));
232	        }
233	    }
234	
235	    // Duplicate check: (course_id, section_code, term, year) is unique.
236	    let dup = sqlx::query(
237	        r#"SELECT 1 FROM sections
238	            WHERE course_id = ? AND section_code = ? AND term = ? AND year = ?
239	            LIMIT 1"#,
240	    )
241	    .bind(input.course_id.to_string())
242	    .bind(input.section_code.trim())
243	    .bind(normalize_term(&input.term))
244	    .bind(input.year)
245	    .fetch_optional(pool)
246	    .await
247	    .map_err(|e| AppError::Database(format!("section dup check: {}", e)))?;
248	    if dup.is_some() {
249	        return Err(AppError::Conflict(format!(
250	            "section {} already exists for {} {} {}",
251	            input.section_code.trim(),
252	            course_code,
253	            input.term,
254	            input.year
255	        )));
256	    }
257	
258	    let mut tx = pool
259	        .begin()
260	        .await
261	        .map_err(|e| AppError::Database(format!("create_section tx: {}", e)))?;
262	
263	    let section_id = Uuid::new_v4();
264	    let version_id = Uuid::new_v4();
265	
266	    sqlx::query(
267	        r#"INSERT INTO sections
268	           (id, course_id, instructor_id, section_code, term, year, capacity, is_active)
269	           VALUES (?, ?, ?, ?, ?, ?, ?, TRUE)"#,
270	    )
271	    .bind(section_id.to_string())
272	    .bind(input.course_id.to_string())
273	    .bind(input.instructor_id.map(|u| u.to_string()))
274	    .bind(input.section_code.trim())
275	    .bind(normalize_term(&input.term))
276	    .bind(input.year)
277	    .bind(input.capacity)
278	    .execute(&mut *tx)
279	    .await
280	    .map_err(|e| AppError::Database(format!("create section insert: {}", e)))?;
281	
282	    sqlx::query(
283	        r#"INSERT INTO section_versions
284	           (id, section_id, version_number, location, schedule_json, notes, state, created_by)
285	           VALUES (?, ?, 1, ?, CAST(? AS JSON), ?, 'draft', ?)"#,
286	    )
287	    .bind(version_id.to_string())
288	    .bind(section_id.to_string())
289	    .bind(input.location.as_deref())
290	    .bind(
291	        input
292	            .schedule_note
293	            .as_deref()
294	            .map(|s| serde_json::json!({ "note": s }).to_string())
295	            .unwrap_or_else(|| "null".to_string()),
296	    )
297	    .bind(input.notes.as_deref())
298	    .bind(principal.user_id.to_string())
299	    .execute(&mut *tx)
300	    .await
301	    .map_err(|e| AppError::Database(format!("create section_version insert: {}", e)))?;
302	
303	    sqlx::query("UPDATE sections SET latest_version_id = ? WHERE id = ?")
304	        .bind(version_id.to_string())
305	        .bind(section_id.to_string())
306	        .execute(&mut *tx)
307	        .await
308	        .map_err(|e| AppError::Database(format!("update latest: {}", e)))?;
309	
310	    tx.commit()
311	        .await
312	        .map_err(|e| AppError::Database(format!("create_section commit: {}", e)))?;
313	
314	    audit_service::record(
315	        pool,
316	        AuditEvent {
317	            actor_id: Some(principal.user_id),
318	            actor_email: Some(&principal.email),
319	            action: "section.create",

