///
/// Every field has a sensible default so the application starts without
/// explicit configuration in development (`docker compose up`). Production
/// deployments MUST override at minimum `jwt_secret` and
/// `field_encryption_key`.
///
/// # Environment variables
///
/// | Variable                  | Default                              | Notes                          |
/// |---------------------------|--------------------------------------|--------------------------------|
/// | `DATABASE_URL`            | `mysql://...@localhost:3306/...`      | MySQL connection string        |
/// | `ATTACHMENT_STORAGE_PATH` | `/data/attachments`                  | Root for file storage          |
/// | `JWT_SECRET`              | `CHANGE_ME_IN_PRODUCTION`            | **Must rotate in production**  |
/// | `JWT_EXPIRATION_HOURS`    | `8`                                  | Token lifetime                 |
/// | `MAX_FAILED_LOGINS`       | `5`                                  | Account lockout threshold      |
/// | `LOCKOUT_DURATION_MINUTES`| `30`                                 | Account lockout window         |
/// | `FIELD_ENCRYPTION_KEY`    | base64url of 32 zero bytes           | **Must rotate in production**  |
/// | `REPORTS_STORAGE_PATH`    | `<ATTACHMENT_STORAGE_PATH>/reports`  | Report artifact storage        |

use std::env;

/// Default dev encryption key: base64url of 32 zero bytes.
/// This is a known-insecure key for development only.
const DEV_ENCRYPTION_KEY: &str = "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA";

#[derive(Debug, Clone)]
pub struct AppConfig {
    pub database_url: String,
    pub attachment_storage_path: String,
    pub jwt_secret: String,
    pub jwt_expiration_hours: u64,
    pub max_failed_logins: u32,
    pub lockout_duration_minutes: u32,
    /// Base64url-encoded 32-byte key for AES-256-GCM field encryption.
    /// Use `openssl rand -base64 32` to generate a production key.
    pub field_encryption_key: String,
    /// Directory where generated report artifact files are stored.
    pub reports_storage_path: String,
}

impl AppConfig {
    pub fn from_env() -> Self {
        let attachment_storage_path = env::var("ATTACHMENT_STORAGE_PATH")
            .unwrap_or_else(|_| "/data/attachments".to_string());

        let reports_storage_path = env::var("REPORTS_STORAGE_PATH")
            .unwrap_or_else(|_| format!("{}/reports", attachment_storage_path));

        Self {
            database_url: env::var("DATABASE_URL").unwrap_or_else(|_| {
                "mysql://scholarly_app:scholarly_app_pass@localhost:3306/scholarly".to_string()
            }),
            attachment_storage_path,
            jwt_secret: env::var("JWT_SECRET")
                .unwrap_or_else(|_| "CHANGE_ME_IN_PRODUCTION".to_string()),
            jwt_expiration_hours: env::var("JWT_EXPIRATION_HOURS")
                .ok()
                .and_then(|v| v.parse().ok())
                .unwrap_or(8),
            max_failed_logins: env::var("MAX_FAILED_LOGINS")
                .ok()
                .and_then(|v| v.parse().ok())
                .unwrap_or(5),
            lockout_duration_minutes: env::var("LOCKOUT_DURATION_MINUTES")
                .ok()
                .and_then(|v| v.parse().ok())
                .unwrap_or(30),
            field_encryption_key: env::var("FIELD_ENCRYPTION_KEY")
                .unwrap_or_else(|_| DEV_ENCRYPTION_KEY.to_string()),
            reports_storage_path,
        }
    }
}
"}

