1	//! Immutable audit log with tamper-evident hash chain.
2	//!
3	//! # Append path
4	//!
5	//! 1. Application services call [`record`] (or one of the `record_*`
6	//!    convenience wrappers) inside the same database transaction that
7	//!    performed the change (or immediately after, for read events).
8	//! 2. [`record`] serializes the event, computes
9	//!    `current_hash = SHA-256(previous_hash || sequence || payload_bytes)`,
10	//!    and writes two rows: one into `audit_logs` and one into
11	//!    `audit_hash_chain`.
12	//! 3. There is **no update path**. `audit_logs` and `audit_hash_chain` are
13	//!    strictly INSERT-only at the application layer; any attempted UPDATE
14	//!    goes through no service method here.
15	//!
16	//! # Verification path
17	//!
18	//! [`verify_chain`] walks the chain in sequence order and recomputes every
19	//! hash. It returns a [`ChainStatus`] describing the first inconsistency,
20	//! if any. The `/api/v1/audit-logs/verify-chain` admin route exposes this.
21	//!
22	//! # Masking
23	//!
24	//! Audit rows returned via the API pass through
25	//! [`crate::application::masking`] helpers so non-admin viewers see masked
26	//! actor emails and IPs.
27	
28	use chrono::{DateTime, NaiveDateTime, Utc};
29	use serde::{Deserialize, Serialize};
30	use sha2::{Digest, Sha256};
31	use sqlx::{MySqlPool, Row};
32	use uuid::Uuid;
33	
34	use crate::errors::{AppError, AppResult};
35	
36	/// Canonical action strings. Use constants, not free-form strings, so the
37	/// set of audit actions is greppable and static.
38	pub mod actions {
39	    pub const LOGIN_SUCCESS: &str = "auth.login.success";
40	    pub const LOGIN_FAILURE: &str = "auth.login.failure";
41	    pub const LOGIN_LOCKED: &str = "auth.login.locked";
42	    pub const LOGOUT: &str = "auth.logout";
