46	    pub const PERMISSION_REVOKE: &str = "rbac.permission.revoke";
47	    pub const ADMIN_CONFIG_WRITE: &str = "admin.config.write";
48	    pub const ADMIN_CONFIG_READ: &str = "admin.config.read";
49	    pub const AUDIT_CHAIN_VERIFY: &str = "audit.chain.verify";
50	    pub const AUDIT_SEARCH: &str = "audit.search";
51	}
