47	fn parse_uuid(s: &str, field: &str) -> AppResult<Uuid> {
48	    Uuid::parse_str(s).map_err(|_| AppError::Validation(format!("{} must be a UUID", field)))
49	}
50	
51	#[get("/?<course_id>&<department_id>&<limit>&<offset>")]
52	pub async fn list_sections(
53	    principal: AuthedPrincipal,
54	    pool: &State<MySqlPool>,
55	    course_id: Option<String>,
56	    department_id: Option<String>,
57	    limit: Option<u32>,
58	    offset: Option<u32>,
59	) -> AppResult<Json<Vec<SectionView>>> {
60	    let p = principal.into_inner();
61	    let cid = match course_id {
62	        Some(ref s) if !s.is_empty() => Some(parse_uuid(s, "course_id")?),
63	        _ => None,
64	    };
65	    let dept = match department_id {
66	        Some(ref s) if !s.is_empty() => Some(parse_uuid(s, "department_id")?),
67	        _ => None,
68	    };
69	    let views = section_service::list_sections(
70	        pool.inner(),
71	        &p,
72	        cid,
73	        dept,
74	        limit.unwrap_or(100),
75	        offset.unwrap_or(0),
76	    )
77	    .await?;
78	    Ok(Json(views))
79	}
