502	pub async fn publish_version(
503	    pool: &MySqlPool,
504	    principal: &Principal,
505	    section_id: Uuid,
506	    version_id: Uuid,
507	) -> AppResult<SectionView> {
508	    require(principal, Capability::SectionPublish)?;
509	    ensure_section_in_scope(pool, principal, section_id).await?;
510	
511	    let mut tx = pool
512	        .begin()
513	        .await
514	        .map_err(|e| AppError::Database(format!("publish tx: {}", e)))?;
515	
516	    let row = sqlx::query(
517	        r#"SELECT state, section_id FROM section_versions WHERE id=? FOR UPDATE"#,
518	    )
519	    .bind(version_id.to_string())
520	    .fetch_optional(&mut *tx)
521	    .await
522	    .map_err(|e| AppError::Database(format!("publish load: {}", e)))?
523	    .ok_or_else(|| AppError::NotFound(format!("section_version {}", version_id)))?;
524	
525	    let state_s: String = row
526	        .try_get("state")
527	        .map_err(|e| AppError::Database(e.to_string()))?;
528	    let sid_s: String = row
529	        .try_get("section_id")
530	        .map_err(|e| AppError::Database(e.to_string()))?;
531	    let current = VersionState::from_db(&state_s).unwrap_or(VersionState::Draft);
532	    if sid_s != section_id.to_string() {
533	        return Err(AppError::NotFound(format!("section_version {}", version_id)));
534	    }
535	    validate_transition(current, VersionState::Published)?;
536	
537	    sqlx::query(
538	        r#"UPDATE section_versions
539	              SET state='archived'
540	            WHERE section_id=? AND state='published' AND id<>?"#,
541	    )
542	    .bind(section_id.to_string())
543	    .bind(version_id.to_string())
544	    .execute(&mut *tx)
545	    .await
546	    .map_err(|e| AppError::Database(format!("archive prior: {}", e)))?;
547	
548	    sqlx::query(
549	        r#"UPDATE section_versions
550	              SET state='published', published_by=?, published_at=NOW()
551	            WHERE id=?"#,
552	    )
553	    .bind(principal.user_id.to_string())
554	    .bind(version_id.to_string())
555	    .execute(&mut *tx)
556	    .await
557	    .map_err(|e| AppError::Database(format!("publish update: {}", e)))?;
558	
559	    sqlx::query("UPDATE sections SET current_version_id=? WHERE id=?")
560	        .bind(version_id.to_string())
561	        .bind(section_id.to_string())
562	        .execute(&mut *tx)
563	        .await
564	        .map_err(|e| AppError::Database(format!("set baseline: {}", e)))?;
565	
566	    tx.commit()
567	        .await
568	        .map_err(|e| AppError::Database(format!("publish commit: {}", e)))?;
569	
570	    audit_service::record(
571	        pool,
572	        AuditEvent {
573	            actor_id: Some(principal.user_id),
574	            actor_email: Some(&principal.email),
575	            action: "section.publish",
576	            target_entity_type: Some("section_version"),
577	            target_entity_id: Some(version_id),
578	            change_payload: Some(serde_json::json!({ "section_id": section_id })),
579	            ip_address: None,
580	            user_agent: None,
581	        },
582	    )
583	    .await?;
584	
585	    get_section_by_id(pool, principal, section_id).await
586	}
