588	pub async fn list_sections(
589	    pool: &MySqlPool,
590	    principal: &Principal,
591	    course_id: Option<Uuid>,
592	    department_id: Option<Uuid>,
593	    limit: u32,
594	    offset: u32,
595	) -> AppResult<Vec<SectionView>> {
596	    require(principal, Capability::SectionRead)?;
597	    let editor = principal_can(principal, Capability::SectionWrite);
598	    let limit = limit.clamp(1, 500) as i64;
599	    let offset = offset as i64;
600	
601	    let scope_dept: Option<Uuid> = if principal.is_admin() || principal.has_role(Role::Librarian) {
602	        department_id
603	    } else {
604	        principal.department_id
605	    };
606	
607	    let mut sql = String::from(
608	        r#"SELECT s.id
609	             FROM sections s
610	             JOIN courses c ON c.id = s.course_id
611	            WHERE 1=1"#,
612	    );
613	    if !editor {
614	        sql.push_str(" AND s.current_version_id IS NOT NULL");
615	    }
616	    if course_id.is_some() {
617	        sql.push_str(" AND s.course_id = ?");
618	    }
619	    if scope_dept.is_some() {
620	        sql.push_str(" AND c.department_id = ?");
621	    }
622	    sql.push_str(" ORDER BY s.year DESC, s.term ASC, s.section_code ASC LIMIT ? OFFSET ?");
623	
624	    let mut q = sqlx::query(&sql);
625	    if let Some(cid) = course_id {
626	        q = q.bind(cid.to_string());
627	    }
628	    if let Some(d) = scope_dept {
629	        q = q.bind(d.to_string());
630	    }
631	    q = q.bind(limit).bind(offset);
632	
633	    let rows = q
634	        .fetch_all(pool)
635	        .await
636	        .map_err(|e| AppError::Database(format!("list_sections: {}", e)))?;
637	
638	    let mut out = Vec::with_capacity(rows.len());
639	    for row in rows {
640	        let id: String = row
641	            .try_get("id")
642	            .map_err(|e| AppError::Database(e.to_string()))?;
643	        let sid = Uuid::parse_str(&id).map_err(|e| AppError::Database(e.to_string()))?;
644	        out.push(get_section_by_id(pool, principal, sid).await?);
645	    }
646	    Ok(out)
647	}
