157	        .user
158	        .as_ref()
159	        .map(|u| u.display_name.clone())
160	        .unwrap_or_else(|| "Unknown user".to_string());
161	
162	    let nav_items = navigation_items();
163	
164	    let on_logout = move |_| {
165	        let token = auth_state
166	            .read()
167	            .token
168	            .clone()
169	            .unwrap_or_default();
170	        spawn(async move {
171	            // Best-effort server-side logout — even if the call fails
172	            // (e.g. already-expired token), we still clear local state.
173	            let _ = auth::logout(&token).await;
174	            auth_state.set(AuthState::default());
175	            AuthState::clear_storage();
176	            navigator.push(AppRoute::Login {});
177	        });
178	    };
179	
180	    rsx! {
181	        div { class: "app-shell",
182	            // ── Sidebar ──────────────────────────────────────
