1	//! HTTP client for the Scholarly backend API.
2	//!
3	//! The frontend is served from the same origin as the backend thanks to
4	//! an nginx reverse proxy that forwards `/api/*` to port `8000`, so
5	//! requests are issued against relative URLs — no CORS concerns.
6	
7	use gloo_net::http::Request;
8	use serde::{de::DeserializeOwned, Deserialize, Serialize};
9	
10	/// Base path for all API calls. Same-origin; nginx proxies upstream.
11	pub const API_BASE: &str = "/api/v1";
12	
13	/// Error type returned by every [`ApiClient`] method.
14	///
15	/// `code` follows the backend error envelope (e.g. `"unauthorized"`,
16	/// `"validation"`). `status` is the raw HTTP status code, or `0` when
17	/// the failure happened before we ever saw a response (network /
18	/// serialization errors).
19	#[derive(Clone, Debug, PartialEq, Eq)]
20	pub struct ApiError {
21	    pub code: String,
22	    pub message: String,
23	    pub status: u16,
24	}
25	
26	impl ApiError {
27	    pub fn network(message: impl Into<String>) -> Self {
28	        Self {
29	            code: "network_error".to_string(),
30	            message: message.into(),
31	            status: 0,
32	        }
33	    }
34	
35	    pub fn decode(message: impl Into<String>) -> Self {
36	        Self {
37	            code: "decode_error".to_string(),
38	            message: message.into(),
39	            status: 0,
40	        }
41	    }
42	
43	    /// Returns `true` if this error indicates the session is no longer
44	    /// valid (HTTP 401 / `unauthorized`).
45	    pub fn is_unauthorized(&self) -> bool {
46	        self.status == 401 || self.code == "unauthorized"
47	    }
48	
49	    /// Returns `true` if this error indicates the current user is
50	    /// forbidden from performing the requested action (HTTP 403).
51	    pub fn is_forbidden(&self) -> bool {
52	        self.status == 403 || self.code == "forbidden"
53	    }
54	}
55	
56	impl std::fmt::Display for ApiError {
57	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
58	        write!(f, "{} ({}): {}", self.code, self.status, self.message)
59	    }
60	}
61	
62	/// Envelope used by the backend for every error response.
63	#[derive(Debug, Deserialize)]
64	struct ErrorEnvelope {
65	    error: ErrorBody,
66	}
67	
68	#[derive(Debug, Deserialize)]
69	struct ErrorBody {
70	    code: Option<String>,
71	    message: Option<String>,
72	    #[allow(dead_code)]
73	    request_id: Option<String>,
74	}
75	
76	/// Lightweight wrapper around `gloo-net` providing convenience methods
77	/// for authenticated requests to the Scholarly backend.
78	#[derive(Clone, Debug, Default)]
79	pub struct ApiClient {
80	    /// Optional bearer token attached to every outbound request.
81	    pub token: Option<String>,
82	}
83	
84	impl ApiClient {
85	    /// Creates a new [`ApiClient`] with the provided token (if any).
86	    pub fn new(token: Option<String>) -> Self {
87	        Self { token }
88	    }
89	
90	    /// Builds an absolute URL for the given API-relative path.
91	    fn url(&self, path: &str) -> String {
92	        if path.starts_with('/') {
93	            format!("{}{}", API_BASE, path)
94	        } else {
95	            format!("{}/{}", API_BASE, path)
96	        }
97	    }
98	
99	    /// Attaches the `Authorization` header when a token is configured.
100	    fn with_auth(&self, mut req: gloo_net::http::RequestBuilder) -> gloo_net::http::RequestBuilder {
101	        if let Some(token) = &self.token {
102	            req = req.header("Authorization", &format!("Bearer {}", token));
103	        }
104	        req
105	    }
106	
107	    /// Issues a `POST` request with a JSON body and decodes a JSON
108	    /// response.
109	    pub async fn post_json<I, O>(&self, path: &str, body: &I) -> Result<O, ApiError>
110	    where
111	        I: Serialize + ?Sized,
112	        O: DeserializeOwned,
113	    {
114	        let url = self.url(path);
115	        let builder = self.with_auth(Request::post(&url));
116	        let request = builder
117	            .json(body)
118	            .map_err(|e| ApiError::decode(format!("failed to serialize body: {e}")))?;
119	        let response = request
120	            .send()
121	            .await
122	            .map_err(|e| ApiError::network(format!("request failed: {e}")))?;
123	
124	        handle_response::<O>(response).await
125	    }
126	
127	    /// Issues a `PUT` request with a JSON body and decodes a JSON
128	    /// response.
129	    pub async fn put_json<I, O>(&self, path: &str, body: &I) -> Result<O, ApiError>
130	    where
131	        I: Serialize + ?Sized,
132	        O: DeserializeOwned,
133	    {
134	        let url = self.url(path);
135	        let builder = self.with_auth(Request::put(&url));
136	        let request = builder
137	            .json(body)
138	            .map_err(|e| ApiError::decode(format!("failed to serialize body: {e}")))?;
139	        let response = request
140	            .send()
141	            .await
142	            .map_err(|e| ApiError::network(format!("request failed: {e}")))?;
143	
144	        handle_response::<O>(response).await
145	    }
146	
147	    /// Issues a `GET` request and decodes a JSON response.
148	    pub async fn get_json<O>(&self, path: &str) -> Result<O, ApiError>
149	    where
150	        O: DeserializeOwned,
151	    {
152	        let url = self.url(path);
153	        let request = self.with_auth(Request::get(&url));
154	        let response = request
155	            .send()
156	            .await
157	            .map_err(|e| ApiError::network(format!("request failed: {e}")))?;
158	
159	        handle_response::<O>(response).await
160	    }
161	
162	    /// Issues a `POST` request with no body and ignores the response
163	    /// body on success (used for idempotent no-content endpoints such
164	    /// as `/auth/logout`).
165	    pub async fn post_no_body(&self, path: &str) -> Result<(), ApiError> {
166	        let url = self.url(path);
167	        let request = self.with_auth(Request::post(&url));
168	        let response = request
169	            .send()
170	            .await
171	            .map_err(|e| ApiError::network(format!("request failed: {e}")))?;
172	
173	        if response.ok() {
174	            return Ok(());
175	        }
176	        Err(parse_error(response).await)
177	    }
178	
179	    /// Issues a `POST` request with an empty JSON body and decodes the
180	    /// response as JSON. Used for action endpoints (e.g. approve,
181	    /// publish) where the backend ignores the request body but returns a
182	    /// hydrated view on success.
183	    pub async fn post_no_body_with_result<O>(&self, path: &str) -> Result<O, ApiError>
184	    where
185	        O: DeserializeOwned,
186	    {
187	        let url = self.url(path);
188	        let builder = self.with_auth(Request::post(&url));
189	        let request = builder
190	            .json(&serde_json::json!({}))
191	            .map_err(|e| ApiError::decode(format!("failed to serialize body: {e}")))?;
192	        let response = request
193	            .send()
194	            .await
195	            .map_err(|e| ApiError::network(format!("request failed: {e}")))?;
196	
197	        handle_response::<O>(response).await
198	    }
199	
200	    /// Issues a `DELETE` request and ignores the response body on
201	    /// success.
202	    pub async fn delete(&self, path: &str) -> Result<(), ApiError> {
203	        let url = self.url(path);
204	        let request = self.with_auth(Request::delete(&url));
205	        let response = request
206	            .send()
207	            .await
208	            .map_err(|e| ApiError::network(format!("request failed: {e}")))?;
209	
210	        if response.ok() {
211	            return Ok(());
212	        }
213	        Err(parse_error(response).await)
214	    }
215	}
216	
217	/// Decodes a successful JSON response, or converts a non-2xx response
218	/// into an [`ApiError`] by parsing the error envelope.
219	async fn handle_response<O>(response: gloo_net::http::Response) -> Result<O, ApiError>
220	where
221	    O: DeserializeOwned,
222	{
223	    if response.ok() {
224	        response
225	            .json::<O>()
226	            .await
227	            .map_err(|e| ApiError::decode(format!("failed to decode response: {e}")))
228	    } else {
229	        Err(parse_error(response).await)
230	    }
231	}
232	
233	/// Extracts an [`ApiError`] from a failed response by parsing the
234	/// backend's error envelope. Falls back to a generic error if the body
235	/// is missing or malformed. Preserves the literal `"unauthorized"` code
236	/// for 401 responses as a stable contract for upstream callers.
237	async fn parse_error(response: gloo_net::http::Response) -> ApiError {
238	    let status = response.status();
239	    let fallback_code = match status {
240	        401 => "unauthorized".to_string(),
241	        403 => "forbidden".to_string(),
242	        _ => "http_error".to_string(),
243	    };
244	    let fallback_message = format!("HTTP {}", status);
245	
246	    match response.json::<ErrorEnvelope>().await {
247	        Ok(envelope) => {
248	            let code = envelope.error.code.unwrap_or_else(|| fallback_code.clone());
249	            let message = envelope
250	                .error
251	                .message
252	                .unwrap_or_else(|| fallback_message.clone());
253	            // For 401 keep the canonical "unauthorized" code regardless
254	            // of whatever the server sent, as per contract.
255	            let code = if status == 401 {
256	                "unauthorized".to_string()
257	            } else {
258	                code
259	            };
260	            ApiError {
261	                code,
262	                message,
263	                status,
264	            }
265	        }
266	        Err(_) => ApiError {
267	            code: fallback_code,
268	            message: fallback_message,
269	            status,
270	        },
271	    }
272	}
