79	        self.roles.iter().map(|r| r.level()).max().unwrap_or(0)
80	    }
81	
82	    /// True if any of the caller's roles meets the minimum level.
83	    pub fn at_least(&self, min: Role) -> bool {
84	        self.max_role_level() >= min.level()
85	    }
