1	//! Password hashing and policy enforcement.
2	//!
3	//! Uses Argon2id with a per-password random salt. Hashes are stored in the
4	//! PHC string format (`$argon2id$v=19$...`) so algorithm parameters are
5	//! self-describing and future upgrades don't require schema changes.
6	//!
7	//! Policy:
8	//! * Minimum length: [`MIN_PASSWORD_LENGTH`] characters.
9	//! * The sentinel hash [`BOOTSTRAP_SENTINEL`] is rejected by `verify_password`
10	//!   — a user whose row still contains that value has never completed
11	//!   bootstrap and cannot log in.
12	
13	use argon2::password_hash::{rand_core::OsRng, PasswordHash, PasswordHasher, PasswordVerifier, SaltString};
14	use argon2::Argon2;
15	
16	use crate::errors::AppError;
17	
18	/// Minimum password length enforced at set/change time.
19	pub const MIN_PASSWORD_LENGTH: usize = 12;
20	
21	/// Placeholder stored in seed rows so no credential material lives in SQL.
22	/// Replaced on first boot by [`crate::infrastructure::bootstrap`].
23	pub const BOOTSTRAP_SENTINEL: &str = "__BOOTSTRAP__";
24	
25	/// Validate a plaintext password against policy. Does not hash.
26	pub fn validate_password_policy(password: &str) -> Result<(), AppError> {
27	    if password.chars().count() < MIN_PASSWORD_LENGTH {
28	        return Err(AppError::Validation(format!(
29	            "password must be at least {} characters long",
30	            MIN_PASSWORD_LENGTH
31	        )));
32	    }
33	    Ok(())
34	}
35	
36	/// Hash a password with Argon2id using a fresh random salt.
37	///
38	/// Returns the PHC-formatted hash string ready for storage in
39	/// `users.password_hash`.
40	pub fn hash_password(password: &str) -> Result<String, AppError> {
41	    validate_password_policy(password)?;
42	    let salt = SaltString::generate(&mut OsRng);
43	    let argon2 = Argon2::default();
44	    argon2
45	        .hash_password(password.as_bytes(), &salt)
46	        .map(|h| h.to_string())
47	        .map_err(|e| AppError::Internal(format!("password hashing failed: {}", e)))
48	}
49	
50	/// Constant-time verification of a plaintext password against a stored hash.
51	///
52	/// Returns `Ok(true)` on match, `Ok(false)` on mismatch, and an
53	/// `AppError::Internal` when the stored hash is malformed or is still the
54	/// bootstrap sentinel (i.e. the account has no real credential yet).
55	pub fn verify_password(password: &str, stored_hash: &str) -> Result<bool, AppError> {
56	    if stored_hash == BOOTSTRAP_SENTINEL {
57	        // Fail closed: a sentinel means bootstrap has not run yet.
58	        return Err(AppError::Internal(
59	            "account has no password set (bootstrap incomplete)".into(),
60	        ));
61	    }
62	    let parsed = PasswordHash::new(stored_hash)
63	        .map_err(|e| AppError::Internal(format!("stored hash is malformed: {}", e)))?;
64	    match Argon2::default().verify_password(password.as_bytes(), &parsed) {
65	        Ok(()) => Ok(true),
66	        Err(argon2::password_hash::Error::Password) => Ok(false),
67	        Err(e) => Err(AppError::Internal(format!("password verification failed: {}", e))),
68	    }
69	}
70	
71	#[cfg(test)]
72	mod tests {
73	    use super::*;
74	
75	    #[test]
76	    fn policy_rejects_short_passwords() {
77	        assert!(validate_password_policy("short").is_err());
78	        assert!(validate_password_policy("elevenchars").is_err()); // 11 chars
79	        assert!(validate_password_policy("twelvecharss").is_ok()); // 12 chars
80	        assert!(validate_password_policy("ChangeMe!Scholarly2026").is_ok());
81	    }
82	
83	    #[test]
84	    fn hash_and_verify_round_trip() {
85	        let password = "CorrectHorseBatteryStaple!";
86	        let hash = hash_password(password).expect("hashing works");
87	        assert!(hash.starts_with("$argon2id$"));
88	        assert!(verify_password(password, &hash).expect("verify works"));
89	        assert!(!verify_password("wrong-password-12", &hash).expect("verify works"));
90	    }
91	
92	    #[test]
93	    fn bootstrap_sentinel_is_rejected() {
94	        let err = verify_password("anything-goes-here", BOOTSTRAP_SENTINEL).unwrap_err();
95	        match err {
96	            AppError::Internal(msg) => assert!(msg.contains("bootstrap")),
97	            _ => panic!("expected Internal error"),
98	        }
99	    }
100	
101	    #[test]
102	    fn hashing_rejects_short_password() {
103	        assert!(hash_password("tooShort").is_err());
104	    }
105	
106	    #[test]
107	    fn hash_uses_unique_salt() {
108	        // Two hashes of the same password must differ because of random salts.
109	        let h1 = hash_password("CorrectHorseBattery1").unwrap();
110	        let h2 = hash_password("CorrectHorseBattery1").unwrap();
111	        assert_ne!(h1, h2);
112	    }
113	}
