// ---------------------------------------------------------------------------
// View types
// ---------------------------------------------------------------------------

#[derive(Serialize)]
pub struct UserProfile {
    pub id: Uuid,
    pub email: String,
    pub display_name: String,
    pub status: String,
    pub roles: Vec<String>,
    pub department_id: Option<Uuid>,
