54	/// Assert that the given object is visible to the principal under `scope`.
55	///
56	/// `owner_id` and `department_id` are the object's attributes. Used by
57	/// service methods that fetch a row by id and then verify visibility
58	/// before returning it.
59	pub fn require_object_visible(
60	    scope: &ScopeFilter,
61	    object_owner_id: Option<Uuid>,
62	    object_department_id: Option<Uuid>,
63	) -> AppResult<()> {
64	    match scope {
65	        ScopeFilter::All => Ok(()),
66	        ScopeFilter::None => Err(AppError::Forbidden),
67	        ScopeFilter::Department(dept) => {
68	            if object_department_id == Some(*dept) {
69	                Ok(())
70	            } else {
71	                Err(AppError::Forbidden)
72	            }
73	        }
74	        ScopeFilter::OwnedBy(uid) => {
75	            if object_owner_id == Some(*uid) {
76	                Ok(())
77	            } else {
78	                Err(AppError::Forbidden)
79	            }
80	        }
81	        ScopeFilter::DepartmentOrOwned {
82	            department_id,
83	            owner_id,
84	        } => {
85	            if object_department_id == Some(*department_id)
86	                || object_owner_id == Some(*owner_id)
87	            {
88	                Ok(())
89	            } else {
90	                Err(AppError::Forbidden)
91	            }
92	        }
93	    }
94	}
