1	//! Audit log search and chain verification routes.
2	//!
3	//! Both routes require `Capability::AuditRead` which, in the Phase 2
4	//! matrix, is granted only to Admin. Chain verification is additionally
5	//! behind `AdminOnly` so it cannot be trivially probed by lower roles.
6	//! Every access writes an audit entry referring back to itself (the
7	//! `AUDIT_SEARCH` / `AUDIT_CHAIN_VERIFY` action).
8	
9	use chrono::{DateTime, Utc};
10	use rocket::serde::json::Json;
11	use rocket::State;
12	use serde::Serialize;
13	use sqlx::MySqlPool;
14	use uuid::Uuid;
15	
16	use crate::api::guards::{AdminOnly, AuthedPrincipal};
17	use crate::application::audit_service::{
18	    self, actions, AuditEvent, AuditLogView, AuditSearch, ChainStatus,
19	};
20	use crate::application::authorization::{self, Capability};
21	use crate::application::masking;
22	use crate::errors::{AppError, AppResult};
23	
24	pub fn routes() -> Vec<rocket::Route> {
25	    routes![list_audit_logs, verify_chain_endpoint]
26	}
27	
28	#[derive(Serialize)]
29	pub struct AuditLogEnvelope {
30	    pub entries: Vec<AuditLogView>,
31	    pub count: usize,
32	}
33	
34	/// GET /api/v1/audit-logs?actor_id=&action=&from=&to=&limit=
35	#[get("/?<actor_id>&<action>&<target_entity_type>&<target_entity_id>&<from>&<to>&<limit>")]
36	pub async fn list_audit_logs(
37	    principal: AuthedPrincipal,
38	    pool: &State<MySqlPool>,
39	    actor_id: Option<String>,
40	    action: Option<String>,
41	    target_entity_type: Option<String>,
42	    target_entity_id: Option<String>,
43	    from: Option<String>,
44	    to: Option<String>,
45	    limit: Option<u32>,
46	) -> AppResult<Json<AuditLogEnvelope>> {
47	    let principal = principal.into_inner();
48	    authorization::require(&principal, Capability::AuditRead)?;
49	
50	    let filter = AuditSearch {
51	        actor_id: parse_uuid_opt(actor_id.as_deref(), "actor_id")?,
52	        action,
53	        target_entity_type,
54	        target_entity_id: parse_uuid_opt(target_entity_id.as_deref(), "target_entity_id")?,
55	        from: parse_rfc3339_opt(from.as_deref(), "from")?,
56	        to: parse_rfc3339_opt(to.as_deref(), "to")?,
57	        limit: limit.unwrap_or(100),
58	    };
59	
60	    let mut entries = audit_service::search(pool.inner(), &filter).await?;
61	
62	    // Apply masking for non-admin viewers. Admin = no redaction.
63	    for row in entries.iter_mut() {
64	        if let Some(ref email) = row.actor_email {
65	            row.actor_email = Some(masking::mask_email_for_audit(email, &principal));
66	        }
67	        row.ip_address = masking::mask_ip_for_audit(row.ip_address.as_deref(), &principal);
68	    }
69	
70	    // Record the search itself to the audit log.
71	    let _ = audit_service::record(
72	        pool.inner(),
73	        AuditEvent {
74	            actor_id: Some(principal.user_id),
75	            actor_email: Some(&principal.email),
76	            action: actions::AUDIT_SEARCH,
77	            target_entity_type: Some("audit_log"),
78	            target_entity_id: None,
79	            change_payload: Some(serde_json::json!({
80	                "count": entries.len(),
81	                "filter": {
82	                    "actor_id": filter.actor_id,
83	                    "action": filter.action,
84	                    "target_entity_type": filter.target_entity_type,
85	                }
86	            })),
87	            ip_address: None,
88	            user_agent: None,
89	        },
90	    )
91	    .await;
92	
93	    let count = entries.len();
94	    Ok(Json(AuditLogEnvelope { entries, count }))
95	}
96	
97	/// GET /api/v1/audit-logs/verify-chain — admin-only chain integrity check.
98	#[get("/verify-chain")]
99	pub async fn verify_chain_endpoint(
100	    admin: AdminOnly,
101	    pool: &State<MySqlPool>,
102	) -> AppResult<Json<ChainStatus>> {
103	    let admin = admin.into_inner();
104	    let status = audit_service::verify_chain(pool.inner()).await?;
105	
106	    let _ = audit_service::record(
107	        pool.inner(),
108	        AuditEvent {
109	            actor_id: Some(admin.user_id),
110	            actor_email: Some(&admin.email),
111	            action: actions::AUDIT_CHAIN_VERIFY,
112	            target_entity_type: Some("audit_chain"),
113	            target_entity_id: None,
114	            change_payload: Some(serde_json::json!({
115	                "total_entries": status.total_entries,
116	                "valid": status.valid,
117	                "broken_at_sequence": status.broken_at_sequence,
118	            })),
119	            ip_address: None,
120	            user_agent: None,
121	        },
122	    )
123	    .await;
124	
125	    Ok(Json(status))
126	}
127	
128	fn parse_uuid_opt(raw: Option<&str>, field: &str) -> AppResult<Option<Uuid>> {
129	    match raw {
130	        None => Ok(None),
131	        Some(s) if s.is_empty() => Ok(None),
132	        Some(s) => Uuid::parse_str(s)
133	            .map(Some)
134	            .map_err(|_| AppError::Validation(format!("{} must be a UUID", field))),
135	    }
136	}
137	
138	fn parse_rfc3339_opt(raw: Option<&str>, field: &str) -> AppResult<Option<DateTime<Utc>>> {
139	    match raw {
140	        None => Ok(None),
141	        Some(s) if s.is_empty() => Ok(None),
142	        Some(s) => DateTime::parse_from_rfc3339(s)
143	            .map(|d| Some(d.with_timezone(&Utc)))
144	            .map_err(|_| AppError::Validation(format!("{} must be RFC3339", field))),
145	    }
146	}
