22	/// Assemble the full Rocket instance: connect to MySQL, run the one-time
23	/// bootstrap routine (replacing seed sentinel password hashes), initialise
24	/// field-level encryption, and mount every route namespace.
25	///
26	/// Phase 6 additions:
27	/// * `FieldEncryption` added as managed state (injected into API handlers).
28	/// * `ReportScheduler` spawned as a background Tokio task.
29	pub async fn build_rocket() -> Rocket<Build> {
30	    let app_config = config::AppConfig::from_env();
31	    tracing::info!(url = %redact_db_url(&app_config.database_url), "connecting to database");
32	
33	    let pool = infrastructure::database::init_pool(&app_config.database_url)
34	        .await
35	        .expect("database pool initialization failed");
36	
37	    // First-boot bootstrap: hash seed passwords if still sentinels.
38	    if let Err(e) = infrastructure::bootstrap::ensure_seed_passwords(&pool).await {
39	        tracing::error!("bootstrap failed: {}", e);
40	        // Startup continues — a failed bootstrap leaves unusable sentinel
41	        // rows, which the password verifier will reject with a clear error.
42	    }
43	
44	    // Phase 6: initialise AES-256-GCM field encryption.
45	    let encryption =
46	        application::encryption::FieldEncryption::from_base64(&app_config.field_encryption_key)
47	            .expect("FIELD_ENCRYPTION_KEY must be a valid base64url-encoded 32-byte key");
48	
49	    if encryption.is_dev_key() {
50	        tracing::warn!(
51	            "FIELD_ENCRYPTION_KEY is the insecure development default. \
52	             Set a real random key in production using: \
53	             openssl rand -base64 32 | tr '+/' '-_' | tr -d '='"
54	        );
55	    }
56	
57	    // Phase 6: spawn the background report scheduler.
58	    // The scheduler polls every ~60 seconds for due report schedules and
59	    // executes them, storing generated artifact files in reports_storage_path.
60	    {
61	        let scheduler = infrastructure::scheduler::ReportScheduler::new(
62	            pool.clone(),
63	            app_config.reports_storage_path.clone(),
64	            encryption.clone(),
65	        );
66	        scheduler.spawn();
67	    }
68	
69	    rocket::build()
70	        .manage(pool)
71	        .manage(app_config)
72	        .manage(encryption)
73	        // ── Auth ──
74	        .mount("/api/v1/auth", api::auth::routes())
75	        // ── Users & RBAC ──
76	        .mount("/api/v1/users", api::users::routes())
77	        .mount("/api/v1/roles", api::roles::routes())
78	        // ── Core domains ──
79	        .mount("/api/v1/journals", api::journals::routes())
80	        .mount("/api/v1/teaching-resources", api::teaching_resources::routes())
81	        .mount("/api/v1/courses", api::courses::routes())
82	        .mount("/api/v1/sections", api::sections::routes())
83	        .mount("/api/v1/attachments", api::attachments::routes())
84	        // ── Operations ──
85	        .mount("/api/v1/checkins", api::checkins::routes())
86	        .mount("/api/v1/metrics", api::metrics::routes())
87	        .mount("/api/v1/dashboards", api::dashboards::routes())
88	        .mount("/api/v1/reports", api::reports::routes())
89	        // ── Administration ──
90	        .mount("/api/v1/audit-logs", api::audit_logs::routes())
91	        .mount("/api/v1/admin/config", api::admin_config::routes())
92	        .mount("/api/v1/admin/retention", api::retention::routes())
