97	/// Strip the password from a database URL for safe logging.
98	fn redact_db_url(url: &str) -> String {
99	    // mysql://user:password@host:port/db  -> mysql://user:***@host:port/db
100	    if let Some(scheme_end) = url.find("://") {
101	        let rest = &url[scheme_end + 3..];
102	        if let Some(at) = rest.find('@') {
103	            let userpass = &rest[..at];
104	            if let Some(colon) = userpass.find(':') {
105	                let user = &userpass[..colon];
106	                let host_part = &rest[at..];
107	                return format!("{}://{}:***{}", &url[..scheme_end], user, host_part);
108	            }
109	        }
110	    }
111	    url.to_string()
112	}
