10	/// Key used to persist [`AuthState`] in browser `localStorage`.
11	const STORAGE_KEY: &str = "scholarly_auth";
12	
13	/// Authentication state — tracks the currently logged-in user and their
14	/// bearer token.
15	#[derive(Clone, Debug, Default, Serialize, Deserialize, PartialEq)]
16	pub struct AuthState {
17	    /// The authenticated user, if any.
18	    pub user: Option<User>,
19	    /// JWT or opaque bearer token for API requests.
20	    pub token: Option<String>,
21	    /// RFC3339 timestamp at which the current token expires.
22	    pub expires_at: Option<String>,
23	}
24	
25	impl AuthState {
26	    /// Returns `true` if a user is currently authenticated — both a
27	    /// bearer token and a hydrated user record are required.
28	    pub fn is_authenticated(&self) -> bool {
29	        self.token.is_some() && self.user.is_some()
30	    }
31	
32	    /// Returns the user's highest-privileged role, if any.
33	    pub fn primary_role(&self) -> Option<Role> {
34	        let user = self.user.as_ref()?;
35	        user.roles
36	            .iter()
37	            .max_by_key(|r| r.level())
38	            .cloned()
39	    }
40	
41	    /// Attempts to hydrate an [`AuthState`] from `localStorage`.
42	    ///
43	    /// Returns [`AuthState::default`] on any failure (missing window,
44	    /// unavailable storage, missing key, malformed JSON).
45	    pub fn load_from_storage() -> AuthState {
46	        let storage = match web_sys::window().and_then(|w| w.local_storage().ok().flatten()) {
47	            Some(s) => s,
48	            None => return AuthState::default(),
49	        };
50	
51	        let raw = match storage.get_item(STORAGE_KEY) {
52	            Ok(Some(s)) => s,
53	            _ => return AuthState::default(),
54	        };
55	
56	        serde_json::from_str::<AuthState>(&raw).unwrap_or_default()
57	    }
58	
59	    /// Persists this [`AuthState`] into `localStorage`. All errors are
60	    /// swallowed — persistence is best-effort.
61	    pub fn save_to_storage(&self) {
62	        let Some(storage) = web_sys::window().and_then(|w| w.local_storage().ok().flatten()) else {
63	            return;
64	        };
65	        if let Ok(json) = serde_json::to_string(self) {
66	            let _ = storage.set_item(STORAGE_KEY, &json);
67	        }
68	    }
69	
70	    /// Removes the persisted auth state from `localStorage`.
71	    pub fn clear_storage() {
72	        if let Some(storage) = web_sys::window().and_then(|w| w.local_storage().ok().flatten()) {
73	            let _ = storage.remove_item(STORAGE_KEY);
74	        }
75	    }
76	}
