1	//! Retention settings page — manage data retention policies.
2	//!
3	//! Admins can:
4	//!   - View all retention policies (entity type, days, action, status).
5	//!   - Inline-edit `retention_days` (saves on Enter or blur).
6	//!   - Toggle `is_active` per policy.
7	//!   - Execute a single policy (dry-run or live).
8	//!   - Execute all policies at once (dry-run or live).
9	//!   - View the last execution summary inline.
10	
11	use dioxus::prelude::*;
12	use dioxus_router::prelude::*;
13	
14	use crate::api::retention::{
15	    self, RetentionExecutionResult, RetentionExecutionSummary, RetentionPolicyView,
16	    UpdateRetentionPolicyInput,
17	};
18	use crate::router::AppRoute;
19	use crate::state::AuthState;
20	
21	// ── Helpers ───────────────────────────────────────────────────────────────────
22	
23	fn action_label(action: &str) -> &'static str {
24	    match action {
25	        "delete" => "Delete",
26	        "anonymize" => "Anonymize",
27	        "flag_for_review" => "Flag for review",
28	        _ => "Unknown",
29	    }
30	}
31	
32	fn entity_label(t: &str) -> &'static str {
33	    match t {
34	        "audit_logs" => "Audit logs",
35	        "sessions" => "Sessions",
36	        "operational_events" => "Operational events",
37	        "report_runs" => "Report runs",
38	        _ => "Unknown",
39	    }
40	}
