42	// ── Component ─────────────────────────────────────────────────────────────────
43	
44	#[component]
45	pub fn RetentionSettings() -> Element {
46	    let mut auth = use_context::<Signal<AuthState>>();
47	    let navigator = use_navigator();
48	
49	    // ── List state ─────────────────────────────────────────────────────
50	    let mut policies = use_signal(Vec::<RetentionPolicyView>::new);
51	    let mut loading = use_signal(|| true);
52	    let mut load_error = use_signal(|| Option::<String>::None);
53	    let mut reload_tick = use_signal(|| 0u32);
54	
55	    // ── Per-policy inline edit: maps policy id → draft string ──────────
56	    // We track which policy is currently being edited and its draft value.
57	    let mut editing_id = use_signal(|| Option::<String>::None);
58	    let mut edit_draft = use_signal(String::new);
59	    let mut save_error = use_signal(|| Option::<String>::None);
60	    let mut save_banner = use_signal(|| Option::<String>::None);
61	    let mut saving = use_signal(|| false);
62	
63	    // ── Execute-all state ─────────────────────────────────────────────
64	    let mut executing_all = use_signal(|| false);
65	    let mut exec_all_summary = use_signal(|| Option::<RetentionExecutionSummary>::None);
66	    let mut exec_all_error = use_signal(|| Option::<String>::None);
67	
68	    // ── Per-policy execute state ──────────────────────────────────────
69	    let mut executing_id = use_signal(|| Option::<String>::None);
70	    let mut per_policy_result = use_signal(|| Option::<RetentionExecutionResult>::None);
71	    let mut per_policy_error = use_signal(|| Option::<String>::None);
72	
73	    // ── Load policies ──────────────────────────────────────────────────
74	    use_effect(move || {
75	        let _tick = reload_tick.read();
76	        let token = match auth.read().token.clone() {
77	            Some(t) => t,
78	            None => return,
79	        };
80	        loading.set(true);
81	        load_error.set(None);
82	        spawn(async move {
83	            match retention::list_policies(&token).await {
84	                Ok(data) => {
85	                    policies.set(data);
86	                    loading.set(false);
87	                }
88	                Err(err) => {
89	                    loading.set(false);
90	                    if err.is_unauthorized() {
91	                        auth.set(AuthState::default());
92	                        AuthState::clear_storage();
93	                        navigator.push(AppRoute::Login {});
94	                        return;
95	                    }
96	                    if err.is_forbidden() {
97	                        navigator.push(AppRoute::ForbiddenPage {});
98	                        return;
99	                    }
100	                    load_error
101	                        .set(Some(format!("Failed to load policies: {}", err.message)));
102	                }
103	            }
104	        });
105	    });
106	
107	    // ── Execute all ────────────────────────────────────────────────────
108	    let do_execute_all = move |dry_run: bool| {
109	        if executing_all() {
110	            return;
111	        }
112	        let token = match auth.read().token.clone() {
113	            Some(t) => t,
114	            None => return,
115	        };
116	        executing_all.set(true);
117	        exec_all_summary.set(None);
118	        exec_all_error.set(None);
119	        per_policy_result.set(None);
120	        spawn(async move {
121	            match retention::execute_all(&token, dry_run).await {
122	                Ok(summary) => {
123	                    executing_all.set(false);
124	                    exec_all_summary.set(Some(summary));
125	                    reload_tick.with_mut(|n| *n += 1);
126	                }
127	                Err(err) => {
128	                    executing_all.set(false);
129	                    exec_all_error
130	                        .set(Some(format!("Execution failed: {}", err.message)));
131	                }
132	            }
133	        });
134	    };
135	
136	    // ── Snapshots ──────────────────────────────────────────────────────
137	    let policies_snapshot = policies.read().clone();
138	    let exec_summary_snap = exec_all_summary.read().clone();
139	    let per_result_snap = per_policy_result.read().clone();
140	
141	    rsx! {
142	        div { class: "page-header library-header",
143	            div {
144	                h1 { "Retention Settings" }
145	                p { class: "text-muted",
146	                    "Configure how long each category of data is retained before automated action."
147	                }
148	            }
149	        }
150	
151	        // ── Feedback banners ───────────────────────────────────────────
152	        if let Some(msg) = save_banner() {
153	            div { class: "save-banner", "{msg}" }
154	        }
155	        if let Some(msg) = save_error() {
156	            div { class: "error-banner", "{msg}" }
157	        }
158	        if let Some(msg) = exec_all_error() {
159	            div { class: "error-banner", "{msg}" }
160	        }
161	        if let Some(msg) = per_policy_error() {
162	            div { class: "error-banner", "{msg}" }
163	        }
164	
165	        // ── Execute-all controls ───────────────────────────────────────
166	        div { class: "retention-exec-controls",
167	            button {
168	                r#type: "button",
169	                class: "primary-button",
170	                disabled: executing_all() || saving(),
171	                onclick: move |_| do_execute_all(true),
172	                if executing_all() {
173	                    "Running dry run…"
174	                } else {
175	                    "Execute All (Dry Run)"
176	                }
177	            }
178	            button {
179	                r#type: "button",
180	                class: "danger-button",
181	                disabled: executing_all() || saving(),
182	                onclick: move |_| do_execute_all(false),
183	                if executing_all() {
184	                    "Executing…"
185	                } else {
186	                    "Execute All (Live)"
187	                }
188	            }
189	        }
190	
191	        // ── All-policies execution summary ─────────────────────────────
192	        if let Some(summary) = exec_summary_snap {
193	            div { class: "retention-summary-box",
194	                h3 {
195	                    if summary.dry_run {
196	                        "Dry-Run Execution Summary"
197	                    } else {
198	                        "Live Execution Summary"
199	                    }
200	                }
201	                dl { class: "course-meta",
202	                    dt { "Policies run" }
203	                    dd { "{summary.policies_run}" }
204	                    dt { "Policies skipped" }
205	                    dd { "{summary.policies_skipped}" }
206	                    dt { "Total rows affected" }
207	                    dd { "{summary.total_rows_affected}" }
208	                    if let Some(files) = summary.total_files_deleted {
209	                        dt { "Files deleted" }
210	                        dd { "{files}" }
211	                    }
212	                    dt { "Executed at" }
213	                    dd { "{summary.executed_at}" }
214	                }
215	                if !summary.results.is_empty() {
216	                    details { class: "retention-summary-details",
217	                        summary { "Per-policy results ({summary.results.len()})" }
218	                        ul { class: "retention-result-list",
219	                            for r in summary.results.iter() {
220	                                li { key: "{r.policy_id}",
221	                                    span { class: "text-muted",
222	                                        "{entity_label(&r.target_entity_type)}"
223	                                    }
224	                                    " — "
225	                                    span { "{r.rows_affected} rows ({r.action})" }
226	                                    if let Some(e) = r.error.as_ref() {
227	                                        span { class: "error-inline", " Error: {e}" }
228	                                    }
229	                                }
230	                            }
231	                        }
232	                    }
233	                }
234	            }
235	        }
236	
237	        // ── Per-policy execute result ──────────────────────────────────
238	        if let Some(result) = per_result_snap {
239	            div { class: "retention-summary-box",
240	                h3 {
241	                    if result.dry_run {
242	                        "Dry-Run Result"
243	                    } else {
244	                        "Live Execution Result"
245	                    }
246	                }
247	                dl { class: "course-meta",
248	                    dt { "Entity type" }
249	                    dd { "{entity_label(&result.target_entity_type)}" }
250	                    dt { "Action" }
251	                    dd { "{result.action}" }
252	                    dt { "Rows affected" }
253	                    dd { "{result.rows_affected}" }
254	                    if let Some(files) = result.files_deleted {
255	                        dt { "Files deleted" }
256	                        dd { "{files}" }
257	                    }
258	                    dt { "Executed at" }
259	                    dd { "{result.executed_at}" }
260	                    if let Some(e) = result.error.as_ref() {
261	                        dt { "Error" }
262	                        dd { class: "error-inline", "{e}" }
263	                    }
264	                }
265	            }
266	        }
267	
268	        // ── Policies table ─────────────────────────────────────────────
269	        if loading() {
270	            p { class: "text-muted", "Loading policies…" }
271	        } else if let Some(msg) = load_error() {
272	            div { class: "error-banner", "{msg}" }
273	        } else if policies_snapshot.is_empty() {
274	            p { class: "text-muted", "No retention policies configured." }
275	        } else {
276	            div { class: "reports-table-wrapper",
277	                table { class: "data-table",
278	                    thead {
279	                        tr {
280	                            th { "Entity type" }
281	                            th { "Retention (days)" }
282	                            th { "Action" }
283	                            th { "Active" }
284	                            th { "Eligible rows" }
285	                            th { "Last executed" }
286	                            th { "" }
287	                        }
288	                    }
289	                    tbody {
290	                        for policy in policies_snapshot.iter().cloned() {
291	                            PolicyRow {
292	                                key: "{policy.id}",
293	                                policy: policy,
294	                                editing_id: editing_id,
295	                                executing_id: executing_id,
296	                                executing_all: executing_all,
297	                                saving: saving,
298	                                edit_draft: edit_draft,
299	                                save_error: save_error,
300	                                per_policy_result: per_policy_result,
301	                                per_policy_error: per_policy_error,
302	                                exec_all_summary: exec_all_summary,
303	                                auth: auth,
304	                                reload_tick: reload_tick,
305	                                save_banner: save_banner,
306	                            }
307	                        }
308	                    }
309	                }
310	            }
311	
312	            // ── Action legend ──────────────────────────────────────────
313	            div { class: "retention-legend",
314	                p {
315	                    span { class: "tag tag--danger", "Delete" }
316	                    " — permanently removes rows from the database."
317	                }
318	                p {
319	                    span { class: "tag tag--warning", "Anonymize" }
320	                    " ⚠ — replaces personally identifiable fields with pseudonymous tokens. Rows are kept but cannot be traced back to individuals."
321	                }
322	                p {
323	                    span { class: "tag", "Flag for review" }
324	                    " — marks rows as eligible for manual review without modifying data."
325	                }
326	            }
327	        }
328	    }
329	}
