331	// ── PolicyRow sub-component ───────────────────────────────────────────────────
332	
333	#[derive(Props, Clone, PartialEq)]
334	struct PolicyRowProps {
335	    policy: RetentionPolicyView,
336	    editing_id: Signal<Option<String>>,
337	    executing_id: Signal<Option<String>>,
338	    executing_all: Signal<bool>,
339	    saving: Signal<bool>,
340	    edit_draft: Signal<String>,
341	    save_error: Signal<Option<String>>,
342	    per_policy_result: Signal<Option<RetentionExecutionResult>>,
343	    per_policy_error: Signal<Option<String>>,
344	    exec_all_summary: Signal<Option<RetentionExecutionSummary>>,
345	    auth: Signal<AuthState>,
346	    reload_tick: Signal<u32>,
347	    save_banner: Signal<Option<String>>,
348	}
349	
350	#[component]
351	fn PolicyRow(props: PolicyRowProps) -> Element {
352	    let policy = props.policy.clone();
353	    let mut editing_id = props.editing_id;
354	    let mut executing_id = props.executing_id;
355	    let executing_all = props.executing_all;
356	    let mut saving = props.saving;
357	    let mut edit_draft = props.edit_draft;
358	    let mut save_error = props.save_error;
359	    let mut per_policy_result = props.per_policy_result;
360	    let mut per_policy_error = props.per_policy_error;
361	    let mut exec_all_summary = props.exec_all_summary;
362	    let mut auth = props.auth;
363	    let mut reload_tick = props.reload_tick;
364	    let mut save_banner = props.save_banner;
365	
366	    let policy_id = policy.id.clone();
367	    let entity = entity_label(&policy.target_entity_type).to_string();
368	    let action = policy.action.clone();
369	    let action_display = action_label(&action).to_string();
370	    let is_active = policy.is_active;
371	    let days = policy.retention_days;
372	    let eligible = policy
373	        .eligible_rows
374	        .map(|n| n.to_string())
375	        .unwrap_or_else(|| "—".to_string());
376	    let last_exec = policy
377	        .last_executed_at
378	        .clone()
379	        .unwrap_or_else(|| "Never".to_string());
380	    let is_editing = editing_id.read().as_deref() == Some(&policy_id);
381	    let is_executing = executing_id.read().as_deref() == Some(&policy_id);
382	    let is_anonymize = action == "anonymize";
383	
384	    let save_id = policy_id.clone();
385	    let toggle_id = policy_id.clone();
386	    let exec_id = policy_id.clone();
387	
388	    // ── Save retention_days helper ─────────────────────────────────────
389	    let do_save_days = move |policy_id: String| {
390	        if saving() {
391	            return;
392	        }
393	        let draft = edit_draft().trim().to_string();
394	        let days: i32 = match draft.parse() {
395	            Ok(n) if n > 0 => n,
396	            _ => {
397	                save_error
398	                    .set(Some("Retention days must be a positive integer.".to_string()));
399	                return;
400	            }
401	        };
402	        let token = match auth.read().token.clone() {
403	            Some(t) => t,
404	            None => return,
405	        };
406	        saving.set(true);
407	        save_error.set(None);
408	        spawn(async move {
409	            let input = UpdateRetentionPolicyInput {
410	                retention_days: Some(days),
411	                ..Default::default()
412	            };
413	            match retention::update_policy(&token, &policy_id, &input).await {
414	                Ok(_) => {
415	                    saving.set(false);
416	                    editing_id.set(None);
417	                    save_banner.set(Some("Retention days updated.".to_string()));
418	                    reload_tick.with_mut(|n| *n += 1);
419	                }
420	                Err(err) => {
421	                    saving.set(false);
422	                    save_error.set(Some(format!("Save failed: {}", err.message)));
423	                }
424	            }
425	        });
426	    };
427	
428	    // ── Toggle is_active helper ────────────────────────────────────────
429	    let do_toggle_active = move |policy_id: String, new_state: bool| {
430	        if saving() {
431	            return;
432	        }
433	        let token = match auth.read().token.clone() {
434	            Some(t) => t,
435	            None => return,
436	        };
437	        saving.set(true);
438	        save_banner.set(None);
439	        save_error.set(None);
440	        spawn(async move {
441	            let input = UpdateRetentionPolicyInput {
442	                is_active: Some(new_state),
443	                ..Default::default()
444	            };
445	            match retention::update_policy(&token, &policy_id, &input).await {
446	                Ok(_) => {
447	                    saving.set(false);
448	                    save_banner.set(Some(if new_state {
449	                        "Policy activated.".to_string()
450	                    } else {
451	                        "Policy deactivated.".to_string()
452	                    }));
453	                    reload_tick.with_mut(|n| *n += 1);
454	                }
455	                Err(err) => {
456	                    saving.set(false);
457	                    save_error.set(Some(format!("Toggle failed: {}", err.message)));
458	                }
459	            }
460	        });
461	    };
462	
463	    rsx! {
464	        tr { key: "{policy_id}",
465	            // Entity type
466	            td { class: "data-table__cell--primary", "{entity}" }
467	
468	            // Retention days — inline editable
469	            td {
470	                if is_editing {
471	                    input {
472	                        r#type: "number",
473	                        class: "inline-input",
474	                        min: "1",
475	                        value: "{edit_draft()}",
476	                        oninput: move |evt| edit_draft.set(evt.value()),
477	                        onkeydown: {
478	                            let sid = save_id.clone();
479	                            move |evt: KeyboardEvent| {
480	                                if evt.key() == Key::Enter {
481	                                    do_save_days(sid.clone());
482	                                }
483	                                if evt.key() == Key::Escape {
484	                                    editing_id.set(None);
485	                                }
486	                            }
487	                        },
488	                        onblur: {
489	                            let sid = save_id.clone();
490	                            move |_: Event<FocusData>| { do_save_days(sid.clone()); }
491	                        },
492	                    }
493	                } else {
494	                    button {
495	                        r#type: "button",
496	                        class: "link-button retention-days-btn",
497	                        title: "Click to edit",
498	                        onclick: {
499	                            let pid = policy_id.clone();
500	                            move |_: Event<MouseData>| {
501	                                editing_id.set(Some(pid.clone()));
502	                                edit_draft.set(days.to_string());
503	                                save_error.set(None);
504	                            }
505	                        },
506	                        "{days}"
507	                    }
508	                }
509	            }
510	
511	            // Action — with warning badge for destructive actions
512	            td {
513	                span {
514	                    class: if action == "delete" {
515	                        "tag tag--danger"
516	                    } else if is_anonymize {
517	                        "tag tag--warning"
518	                    } else {
519	                        "tag"
520	                    },
521	                    "{action_display}"
522	                }
523	                if is_anonymize {
524	                    span {
525	                        class: "retention-warn",
526	                        title: "Anonymize replaces PII with pseudonymous values but keeps the row.",
527	                        " ⚠"
528	                    }
529	                }
530	            }
531	
532	            // Active toggle
533	            td {
534	                button {
535	                    r#type: "button",
536	                    class: if is_active {
537	                        "toggle-btn toggle-btn--on"
538	                    } else {
539	                        "toggle-btn toggle-btn--off"
540	                    },
541	                    disabled: saving(),
542	                    onclick: {
543	                        let tid = toggle_id.clone();
544	                        move |_: Event<MouseData>| { do_toggle_active(tid.clone(), !is_active); }
545	                    },
546	                    if is_active { "Active" } else { "Inactive" }
547	                }
548	            }
549	
550	            // Eligible rows
551	            td { class: "text-muted", "{eligible}" }
552	
553	            // Last executed
554	            td { class: "text-muted", "{last_exec}" }
555	
556	            // Per-policy execute
557	            td { class: "retention-exec-cell",
558	                button {
559	                    r#type: "button",
560	                    class: "link-button",
561	                    disabled: is_executing || executing_all(),
562	                    title: "Dry run — preview only",
563	                    onclick: {
564	                        let eid = exec_id.clone();
565	                        move |_: Event<MouseData>| {
566	                            if executing_id.read().is_some() || executing_all() {
567	                                return;
568	                            }
569	                            let token = match auth.read().token.clone() {
570	                                Some(t) => t,
571	                                None => return,
572	                            };
573	                            executing_id.set(Some(eid.clone()));
574	                            per_policy_result.set(None);
575	                            per_policy_error.set(None);
576	                            exec_all_summary.set(None);
577	                            let eid_async = eid.clone();
578	                            spawn(async move {
579	                                match retention::execute_policy(&token, &eid_async, true).await {
580	                                    Ok(result) => {
581	                                        executing_id.set(None);
582	                                        per_policy_result.set(Some(result));
583	                                    }
584	                                    Err(err) => {
585	                                        executing_id.set(None);
586	                                        per_policy_error.set(Some(format!(
587	                                            "Execute failed: {}",
588	                                            err.message
589	                                        )));
590	                                    }
591	                                }
592	                            });
593	                        }
594	                    },
595	                    if is_executing { "Running…" } else { "Dry run" }
596	                }
597	                span { class: "text-muted", " · " }
598	                button {
599	                    r#type: "button",
600	                    class: "danger-button danger-button--sm",
601	                    disabled: is_executing || executing_all(),
602	                    title: "Execute live — commits changes",
603	                    onclick: {
604	                        let eid = exec_id.clone();
605	                        move |_: Event<MouseData>| {
606	                            if executing_id.read().is_some() || executing_all() {
607	                                return;
608	                            }
609	                            let token = match auth.read().token.clone() {
610	                                Some(t) => t,
611	                                None => return,
612	                            };
613	                            executing_id.set(Some(eid.clone()));
614	                            per_policy_result.set(None);
615	                            per_policy_error.set(None);
616	                            exec_all_summary.set(None);
617	                            let eid_async = eid.clone();
618	                            spawn(async move {
619	                                match retention::execute_policy(&token, &eid_async, false).await {
620	                                    Ok(result) => {
621	                                        executing_id.set(None);
622	                                        per_policy_result.set(Some(result));
623	                                        reload_tick.with_mut(|n| *n += 1);
624	                                    }
625	                                    Err(err) => {
626	                                        executing_id.set(None);
627	                                        per_policy_error.set(Some(format!(
628	                                            "Execute failed: {}",
629	                                            err.message
630	                                        )));
631	                                    }
632	                                }
633	                            });
634	                        }
635	                    },
636	                    if is_executing { "Running…" } else { "Execute" }
637	                }
638	            }
639	        }
640	    }
641	}
