1	//! Login page — user authentication.
2	//!
3	//! This page is rendered *without* the main layout sidebar so that
4	//! unauthenticated users see a clean, focused login experience.
5	
6	use dioxus::prelude::*;
7	use dioxus_router::prelude::*;
8	
9	use crate::api::auth;
10	use crate::router::AppRoute;
11	use crate::state::AuthState;
12	
13	/// Returns `true` if `email` looks vaguely like an address (a single
14	/// `@` with text on both sides and a dot in the domain). This is a
15	/// client-side convenience check only — the backend is always the
16	/// source of truth.
17	fn is_valid_email(email: &str) -> bool {
18	    let trimmed = email.trim();
19	    let Some(at) = trimmed.find('@') else {
20	        return false;
21	    };
22	    let (local, domain) = trimmed.split_at(at);
23	    let domain = &domain[1..];
24	    !local.is_empty() && !domain.is_empty() && domain.contains('.')
25	}
