27	/// Renders the login form and handles credential submission.
28	#[component]
29	pub fn Login() -> Element {
30	    let mut auth_state = use_context::<Signal<AuthState>>();
31	    let navigator = use_navigator();
32	
33	    let mut email = use_signal(String::new);
34	    let mut password = use_signal(String::new);
35	    let mut error = use_signal(|| Option::<String>::None);
36	    let mut submitting = use_signal(|| false);
37	
38	    let on_submit = move |evt: FormEvent| {
39	        evt.prevent_default();
40	
41	        if submitting() {
42	            return;
43	        }
44	
45	        let email_val = email().trim().to_string();
46	        let password_val = password();
47	
48	        if !is_valid_email(&email_val) {
49	            error.set(Some("Please enter a valid email address.".to_string()));
50	            return;
51	        }
52	        if password_val.len() < 12 {
53	            error.set(Some(
54	                "Password must be at least 12 characters long.".to_string(),
55	            ));
56	            return;
57	        }
58	
59	        error.set(None);
60	        submitting.set(true);
61	
62	        spawn(async move {
63	            match auth::login(email_val, password_val).await {
64	                Ok((token, expires_at, user)) => {
65	                    auth_state.with_mut(|s| {
66	                        s.token = Some(token);
67	                        s.expires_at = Some(expires_at);
68	                        s.user = Some(user);
69	                    });
70	                    auth_state.read().save_to_storage();
71	                    submitting.set(false);
72	                    navigator.push(AppRoute::Dashboard {});
73	                }
74	                Err(err) => {
75	                    submitting.set(false);
76	                    error.set(Some(err.message));
77	                }
78	            }
79	        });
80	    };
81	
82	    rsx! {
83	        div { class: "login-page",
84	            div { class: "login-card",
85	                h1 { class: "login-card__brand", "Scholarly" }
86	                p { class: "login-card__subtitle",
87	                    "Sign in to access the library resources system."
88	                }
89	
90	                if let Some(msg) = error() {
91	                    div { class: "login-error", "{msg}" }
92	                }
93	
94	                form {
95	                    class: "login-form",
96	                    onsubmit: on_submit,
97	
98	                    label { r#for: "email", "Email" }
99	                    input {
100	                        id: "email",
101	                        r#type: "email",
102	                        name: "email",
103	                        autocomplete: "username",
104	                        required: true,
105	                        value: "{email}",
106	                        oninput: move |evt| email.set(evt.value()),
107	                    }
108	
109	                    label { r#for: "password", "Password" }
110	                    input {
111	                        id: "password",
112	                        r#type: "password",
113	                        name: "password",
114	                        autocomplete: "current-password",
115	                        required: true,
116	                        minlength: "12",
117	                        value: "{password}",
118	                        oninput: move |evt| password.set(evt.value()),
119	                    }
120	
121	                    button {
122	                        r#type: "submit",
123	                        disabled: submitting(),
124	                        if submitting() { "Signing in..." } else { "Sign in" }
125	                    }
126	                }
127	
128	                p { class: "login-card__hint",
129	                    "Default seed passwords are documented in the README."
130	                }
131	            }
132	        }
133	    }
134	}
